#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use URI::Escape;

my $cgi = new CGI;
my $next = $cgi->param('next') || '/';

# Validate the redirect URL to prevent open redirect vulnerabilities
my $redirect_url = validate_redirect_url($next);

print "Location: $redirect_url\n\n";

sub validate_redirect_url {
    my ($url) = @_;
    
    # If no URL provided, default to home
    return '/index.html' if !$url || $url eq '';
    
    # If URL starts with /, allow it (relative path)
    return $url if $url =~ /^\//;
    
    # If URL starts with http:// or https://, validate it
    if ($url =~ /^https?:\/\//) {
        # Basic validation - only allow URLs from our own domain
        # You may need to adjust this based on your domain
        if ($url =~ /^https?:\/\/(localhost|127\.0\.0\.1|yourdomain\.com)/) {
            return $url;
        } else {
            # Invalid domain, redirect to home
            return '/index.html';
        }
    }
    
    # Default fallback
    return '/index.html';
}